// Aggregate case activities from today
const output = $input.first().json.stdout || '';
if (!output.trim()) {
  return [{ json: { hasActivity: false, activities: [] } }];
}

const files = output.split('\n').filter(f => f);
const fs = require('fs');
const activities = [];

for (const filePath of files) {
  const content = fs.readFileSync(filePath, 'utf8');
  const fileName = filePath.split('/').pop();

  // Extract matter and activity type from filename
  // Format: case_[matter]_[type]_[timestamp].md
  const parts = fileName.replace('.md', '').split('_');

  activities.push({
    matter: parts[1] || 'Unknown',
    type: parts[2] || 'note',
    fileName: fileName,
    content: content.substring(0, 500) // First 500 chars
  });
}

return [{ json: { hasActivity: true, activities: activities } }];

// Generate end-of-day digest email
const data = $input.first().json;
const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

if (!data.hasActivity) {
  return [{
    json: {
      subject: `📋 Daily Case Digest - No activity`,
      body: `📋 CASE ACTIVITY DIGEST - ${today}\n\n✅ No case activity recorded today. Have a great evening!\n\n---\nGenerated by n8n Legal Automation`,
      to: process.env.ATTORNEY_EMAIL || 'attorney@lawfirm.com'
    }
  }];
}

// Group by matter
const byMatter = {};
data.activities.forEach(act => {
  if (!byMatter[act.matter]) {
    byMatter[act.matter] = [];
  }
  byMatter[act.matter].push(act);
});

let emailBody = `📋 CASE ACTIVITY DIGEST - ${today}\n\n`;
emailBody += `Total activities: ${data.activities.length}\n\n`;

for (const matter in byMatter) {
  const acts = byMatter[matter];
  emailBody += `📁 ${matter.toUpperCase()} (${acts.length} activities)\n`;
  acts.forEach(act => {
    emailBody += `  • ${act.type}: ${act.fileName}\n`;
  });
  emailBody += `\n`;
}

emailBody += `---\nGenerated by n8n Legal Automation`;

return [{
  json: {
    subject: `📋 Daily Case Digest - ${data.activities.length} activities`,
    body: emailBody,
    to: process.env.ATTORNEY_EMAIL || 'attorney@lawfirm.com'
  }
}];
